#define AMB_TEMP 80.0f

__kernel void hotspotOpt1(__global const float *pIn,
                          __global float *tIn,
                          __global float *tOut,
                          const float stepDivCap,
                          const int nx,
                          const int ny,
                          const int nz,
                          const float ce,
                          const float cw,
                          const float cn,
                          const float cs,
                          const float ct,
                          const float cb,
                          const float cc)
{
    if (get_global_id(0) != 0 || get_global_id(1) != 0)
        return;

    for (int z = 0; z < nz; z++) {
        for (int y = 0; y < ny; y++) {
            for (int x = 0; x < nx; x++) {
                int c = x + y * nx + z * nx * ny;

                int w = (x == 0)      ? c : c - 1;
                int e = (x == nx - 1) ? c : c + 1;
                int n = (y == 0)      ? c : c - nx;
                int s = (y == ny - 1) ? c : c + nx;
                int b = (z == 0)      ? c : c - nx * ny;
                int t = (z == nz - 1) ? c : c + nx * ny;

                tOut[c] = cc * tIn[c]
                        + cw * tIn[w]
                        + ce * tIn[e]
                        + cn * tIn[n]
                        + cs * tIn[s]
                        + cb * tIn[b]
                        + ct * tIn[t]
                        + stepDivCap * pIn[c]
                        + ct * AMB_TEMP;
            }
        }
    }

    int total = nx * ny * nz;
    for (int i = 0; i < total; i++) {
        tIn[i] = tOut[i];
    }
}
